import { render, screen } from '@testing-library/react';
import '@testing-library/jest-dom';
import App from './App';

describe('CSS Tooltip', () => {
  beforeEach(() => {
    render(<App />);
  });

  it('tooltip wrapper is positioned relative', () => {
    expect(getComputedStyle(screen.getByTestId('tooltip')).position).toBe('relative');
  });

  it('tooltip content is hidden by default', () => {
    const content = screen.getByTestId('tooltip-content');
    const styles = getComputedStyle(content);
    expect(styles.opacity).toBe('0');
    expect(styles.visibility).toBe('hidden');
  });

  it('tooltip content is positioned absolutely', () => {
    expect(getComputedStyle(screen.getByTestId('tooltip-content')).position).toBe('absolute');
  });

  it('tooltip has dark background', () => {
    expect(getComputedStyle(screen.getByTestId('tooltip-content')).backgroundColor).toBe('rgb(31, 41, 55)');
  });

  it('tooltip has white text', () => {
    expect(getComputedStyle(screen.getByTestId('tooltip-content')).color).toBe('rgb(255, 255, 255)');
  });

  it('tooltip has border-radius', () => {
    expect(getComputedStyle(screen.getByTestId('tooltip-content')).borderRadius).toBe('0.375rem');
  });

  it('tooltip has nowrap', () => {
    expect(getComputedStyle(screen.getByTestId('tooltip-content')).whiteSpace).toBe('nowrap');
  });

  it('tooltip has transition', () => {
    const transition = getComputedStyle(screen.getByTestId('tooltip-content')).transition;
    expect(transition).toMatch(/opacity/);
  });
});

